3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	
6	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
16	const COMPONENT_BLOCK_SIZE = 3;
17	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
18	const CURSED_SURCHARGE_RATE = 0.5;
19	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
20	const HIGH_ENCHANTMENT_THRESHOLD = 5;
21	const LOYALTY_DISCOUNT_RATE = 0.2;
22	const LOYALTY_YEARS_THRESHOLD = 2;
23	
24	function loyaltyDiscountFor(yearsInsured: number, baseTotal: number): number {
25	  return yearsInsured >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
26	}
27	
28	function withFirstInsurance(basePremium: number): number {
29	  return basePremium + basePremium * FIRST_INSURANCE_RATE;
30	}
31	
32	function premiumForTypeGroup(type: string, count: number): number {
33	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
34	    return withFirstInsurance(COMPONENT_BLOCK_BASE_PREMIUM);
35	  }
36	  return count * withFirstInsurance(BASE_PREMIUM_BY_ITEM_TYPE[type]);
37	}
38	
39	type Item = { type: string; cursed?: boolean; enchantment?: number };
40	
41	function surchargeRateForItem(item: Item): number {
42	  const cursedRate = item.cursed ? CURSED_SURCHARGE_RATE : 0;
43	  const enchantmentRate =
44	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
45	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
46	      : 0;
47	  return cursedRate + enchantmentRate;
48	}
49	
50	function surchargeForItem(item: Item): number {
51	  return BASE_PREMIUM_BY_ITEM_TYPE[item.type] * surchargeRateForItem(item);
52	}
53	
54	export function runScenario(scenario: any): unknown {
55	  const items: Item[] = scenario.items ?? [];
56	  const countsByType: Record<string, number> = {};
57	  let surchargesTotal = 0;
58	  for (const item of items) {
59	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
60	    surchargesTotal += surchargeForItem(item);
61	  }
62	  let itemsTotal = 0;
63	  let baseTotal = 0;
64	  for (const type of Object.keys(countsByType)) {
65	    const count = countsByType[type];
66	    itemsTotal += premiumForTypeGroup(type, count);
67	    baseTotal += count * BASE_PREMIUM_BY_ITEM_TYPE[type];
68	  }
69	  const yearsInsured = scenario.customer?.yearsInsured ?? 0;
70	  const loyaltyDiscount = loyaltyDiscountFor(yearsInsured, baseTotal);
71	  return {
72	    premium: Math.ceil(itemsTotal + surchargesTotal - loyaltyDiscount + PROCESSING_FEE),
73	  };
74	}
